// // This module implements a 2-to-1 multiplexer that selects between two input signals, D0 and D1, based on the control signal ctrl. However, the actual behavior is reversed; when ctrl is low (0), the output S takes the value of D1, and when ctrl is high (1), the output S takes the value of D0.
module top_module(ctrl,
    D0,
    D1,
    S);input ctrl;
  input [0:0] D0;
  input [0:0] D1;
  output [0:0] S;

  // Use a conditional assign statement instead of LUT3
  assign S = (ctrl) ? D1 : D0;

endmodule
